import source


def test_source_module_imports():
    assert source is not None


def test_powerset_contains_all_subsets():
    """The powerset of a two-element list should contain four subsets, including the empty set."""
    result = source.powerset([1, 2])
    # Convert each subset to a frozenset for order‑independent comparison
    result_sets = {frozenset(subset) for subset in result}
    expected_sets = {frozenset(), frozenset({1}), frozenset({2}), frozenset({1, 2})}
    assert result_sets == expected_sets
    assert len(result) == 4
